from __future__ import annotations
import functools
import logging
import threading
from typing import Any, Callable, Iterator, Protocol, Set


class BenchmarkHook(Protocol):
    def on_call_start(self, layer: str, plugin_name: str, method: str, args: tuple, kwargs: dict) -> Any
    def on_call_end(self, context: Any, result: Any, error: Exception | None) -> None


class CachingHook(Protocol):
    def get_cached_result(self, layer: str, plugin_name: str, method: str, args: tuple, kwargs: dict) -> Any
    def cache_result(self, layer: str, plugin_name: str, method: str, args: tuple, kwargs: dict, result: Any) -> None

class InstrumentedProxy:
    def __init__(self, target: Any, layer: str, plugin_name: str, methods_to_track: set[str] | None):
        self._target = target
        self._layer = layer
        self._plugin_name = plugin_name
        self._methods_to_track = methods_to_track or set()

    def __getattr__(self, name: str) -> Any:
        attr = getattr(self._target, name)
        if name in self._methods_to_track:
            return self._wrap_method(attr, name)
        return attr

    def _wrap_method(self, method: Callable, method_name: str) -> Callable:
        @functools.wraps(method)
        def wrapper(*args, **kwargs):
            context = None
            try:
                context = self._call_start(method_name, args, kwargs)
                result = method(*args, **kwargs)
                self._call_end(context, result, None)
                return result
            except Exception as e:
                self._call_end(context, None, e)
                raise
        return wrapper

    def _call_start(self, method_name: str, args: tuple, kwargs: dict) -> Any:
        hooks = get_hooks()
        context = None
        for hook in hooks:
            if hasattr(hook, 'on_call_start'):
                try:
                    new_context = hook.on_call_start(
                        self._layer,
                        self._plugin_name,
                        method_name,
                        args,
                        kwargs
                    )
                    context = new_context if context is None else context
                except Exception as e:
                    logging.getLogger(__name__).warning(f"Hook on_call_start failed: {e}")
        return context

    def _call_end(self, context: Any, result: Any, error: Exception | None) -> None:
        hooks = get_hooks()
        for hook in hooks:
            if hasattr(hook, 'on_call_end'):
                try:
                    hook.on_call_end(context, result, error)
                except Exception as e:
                    logging.getLogger(__name__).warning(f"Hook on_call_end failed: {e}")

    def __repr__(self) -> str:
        return f"InstrumentedProxy({self._target})"

    def __str__(self) -> str:
        return str(self._target)


# Global registry for hooks
_hooks = threading.local()

def register_hook(hook: BenchmarkHook) -> None:
    if not hasattr(_hooks, 'hooks'):
        _hooks.hooks = []
    _hooks.hooks.append(hook)


def unregister_hook(hook: BenchmarkHook) -> None:
    if hasattr(_hooks, 'hooks'):
        try:
            _hooks.hooks.remove(hook)
        except ValueError:
            pass


def clear_hooks() -> None:
    if hasattr(_hooks, 'hooks'):
        delattr(_hooks, 'hooks')


def has_hooks() -> bool:
    return hasattr(_hooks, 'hooks') and len(get_hooks()) > 0


def get_hooks() -> list[BenchmarkHook]:
    if not hasattr(_hooks, 'hooks'):
        _hooks.hooks = []
    return _hooks.hooks


def maybe_wrap(target: Any, layer: str, plugin_name: str, methods_to_track: set[str] | None) -> Any:
    if has_hooks():
        return wrap(target, layer, plugin_name, methods_to_track)
    return target


def wrap(target: Any, layer: str, plugin_name: str, methods_to_track: set[str] | None) -> InstrumentedProxy:
    return InstrumentedProxy(target, layer, plugin_name, methods_to_track)

